# Worked focus: http-py-field-semantics — Handle field names, repeated lines, combination rules, whitespace, size, and hop-by-hop boundaries by specification. Demonstrate the result through Python 3.14 urllib, http.client, ssl, typed protocols, and fixture transports.
def worked_http_py_fields_representations_3(content_type: str, accepted_types: set[str], body_bytes: int) -> dict[str, object]:
    assert isinstance(content_type, str) and isinstance(body_bytes, int)
    media_type = content_type.partition(";")[0].strip().casefold()
    accepted = 0 <= body_bytes <= 1_048_576 and media_type in accepted_types
    return {"media_type": media_type, "accepted": accepted}

